{
  "schemaVersion": 3,
  "arcId": "arc_1_khoi_nghiep_ca_dat",
  "startChapter": 1,
  "endChapter": 30,
  "direction": "Từ kẻ nhặt cá dạt vô danh với hai bàn tay trắng, Lâm dùng kiến thức bảo quản thủ công để kiếm những đồng vốn đầu tiên, nâng cấp công cụ từ thúng tre lên xe kéo, xây dựng trạm thu mua nhỏ và bắt đầu thay đổi nhận thức đánh bắt tại bến.",
  "terminalChange": "Lâm sở hữu một trạm thu mua lợp lá tại bến cá, có xe kéo tay và chen chân mua được đá lạnh. Vợ Mai được bồi bổ, sức khỏe cải thiện rõ rệt và bắt đầu quản lý tiền bạc. Uy tín của Lâm tại bến được xác lập.",
  "activeConflicts": [
    {
      "id": "conflict_bon_bycatch",
      "actorIds": [
        "char_lam",
        "char_bon"
      ],
      "objective": "Lâm muốn mua lại mẻ cá dạt giá rẻ để bảo quản bán kiếm lời, trong khi Bốn muốn xả hàng nhanh gọn không mất thời gian.",
      "leverage": "Lâm có khả năng dọn sạch bến nhanh chóng giúp Bốn tiết kiệm thời gian, Bốn nắm giữ nguồn cung cá dạt lớn.",
      "nextMove": "Lâm chuẩn bị sẵn thúng tre lót bèo tây và tiền lẻ để mua đứt mẻ cá dạt ngay khi tàu Bốn cập bến."
    },
    {
      "id": "conflict_hai_dock_fee",
      "actorIds": [
        "char_lam",
        "char_hai"
      ],
      "objective": "Hải muốn duy trì trật tự và thu phí bến bãi đầy đủ, Lâm cần một chỗ ngồi tốt để phân loại cá mà không bị chèn ép.",
      "leverage": "Hải có quyền quyết định vị trí tại bến, Lâm có khả năng giữ bến sạch sẽ và đóng phí sòng phẳng khi bắt đầu có lãi.",
      "nextMove": "Lâm chủ động dọn dẹp khu vực phân loại cá và nộp phí bến bãi đầy đủ cho Hải ngay sau chuyến bán cá đầu tiên có lời."
    }
  ],
  "duePromiseIds": [
    "prom_wife_health"
  ],
  "progressionBudget": [
    {
      "signal": "Chất lượng bữa ăn từ cháo loãng lên cơm thịt",
      "requiredChange": "Lâm bán được mẻ cá đầu tiên, mua gạo và thịt lợn về nấu bữa cơm tươm tất cho Mai, giúp cô hồi phục thể lực."
    },
    {
      "signal": "Nâng cấp công cụ từ thúng tre lên xe kéo rồi trạm thu mua",
      "requiredChange": "Lâm tích lũy vốn từ việc bán cá dạt, mua xe kéo tay để tăng sản lượng, sau đó dựng một trạm lợp lá tại bến."
    },
    {
      "signal": "Quyền lực tại bến từ nhặt cá thừa đến bao tiêu",
      "requiredChange": "Lâm gom đủ tiền cọc mua đá lạnh từ nhà máy, bắt đầu thu mua cá đạt kích cỡ và thuyết phục bạn thuyền bỏ lưới tận diệt."
    }
  ]
}
